      clientName: '@mycompany/result-front-exams',
      version:    '3.31.6'
    }),
    new HttpLink({
      uri:         'https://bff.mycompany.com/graphql',
      credentials: 'include'
    })
  ]),
  cache: new InMemoryCache(),
